import{_ as i,o,c as t,ag as h}from"./chunks/framework.nZ6LtKJQ.js";const u=JSON.parse('{"title":"Quản lý người dùng","description":"","frontmatter":{},"headers":[],"relativePath":"manage-users.md","filePath":"manage-users.md","lastUpdated":null}'),a={name:"manage-users.md"};function l(s,n,r,g,e,c){return o(),t("div",null,[...n[0]||(n[0]=[h('<h1 id="quan-ly-nguoi-dung" tabindex="-1">Quản lý người dùng <a class="header-anchor" href="#quan-ly-nguoi-dung" aria-label="Permalink to &quot;Quản lý người dùng&quot;">​</a></h1><h2 id="xem-danh-sach-nguoi-dung" tabindex="-1">Xem danh sách người dùng <a class="header-anchor" href="#xem-danh-sach-nguoi-dung" aria-label="Permalink to &quot;Xem danh sách người dùng&quot;">​</a></h2><p>Vào <strong>Người dùng</strong> trên sidebar Admin. Danh sách hiển thị tất cả tài khoản trong hệ thống với bộ lọc theo:</p><ul><li><strong>Vai trò:</strong> Học sinh / Giáo viên / Admin</li><li><strong>Trạng thái:</strong> Đang hoạt động / Bị khoá</li><li><strong>Tìm kiếm:</strong> Theo tên hoặc email</li></ul><h2 id="tao-tai-khoan-moi" tabindex="-1">Tạo tài khoản mới <a class="header-anchor" href="#tao-tai-khoan-moi" aria-label="Permalink to &quot;Tạo tài khoản mới&quot;">​</a></h2><ol><li>Nhấn <strong>Thêm người dùng</strong></li><li>Điền thông tin: <ul><li>Họ và tên</li><li>Email (dùng để đăng nhập)</li><li>Vai trò: Học sinh / Giáo viên</li><li>Mật khẩu tạm (người dùng có thể đổi sau)</li></ul></li><li>Nhấn <strong>Tạo tài khoản</strong></li></ol><div class="tip custom-block"><p class="custom-block-title">Tạo nhiều tài khoản cùng lúc</p><p>Dùng tính năng <strong>Nhập từ file Excel</strong> để tạo hàng loạt tài khoản học sinh. Tải file mẫu, điền thông tin theo đúng định dạng rồi tải lên.</p></div><h2 id="chinh-sua-tai-khoan" tabindex="-1">Chỉnh sửa tài khoản <a class="header-anchor" href="#chinh-sua-tai-khoan" aria-label="Permalink to &quot;Chỉnh sửa tài khoản&quot;">​</a></h2><ol><li>Tìm người dùng → nhấn ✏️ <strong>Chỉnh sửa</strong></li><li>Cập nhật thông tin hoặc <strong>đặt lại mật khẩu</strong></li><li>Nhấn <strong>Lưu</strong></li></ol><h2 id="khoa-mo-khoa-tai-khoan" tabindex="-1">Khoá / Mở khoá tài khoản <a class="header-anchor" href="#khoa-mo-khoa-tai-khoan" aria-label="Permalink to &quot;Khoá / Mở khoá tài khoản&quot;">​</a></h2><ul><li>Nhấn biểu tượng 🔒 để <strong>khoá</strong> tài khoản — người dùng không đăng nhập được</li><li>Nhấn biểu tượng 🔓 để <strong>mở khoá</strong></li></ul><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>Khoá tài khoản giáo viên sẽ ảnh hưởng đến tất cả lớp học do giáo viên đó phụ trách. Thông báo cho học sinh liên quan trước khi thực hiện.</p></div><h2 id="xoa-tai-khoan" tabindex="-1">Xoá tài khoản <a class="header-anchor" href="#xoa-tai-khoan" aria-label="Permalink to &quot;Xoá tài khoản&quot;">​</a></h2><ol><li>Nhấn 🗑️ <strong>Xoá</strong> cạnh tài khoản cần xoá</li><li>Xác nhận</li></ol><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>Xoá tài khoản là <strong>không thể phục hồi</strong>. Tất cả dữ liệu liên quan (bài làm, điểm số) sẽ bị xoá vĩnh viễn. Cân nhắc <strong>khoá tài khoản</strong> thay vì xoá nếu chỉ muốn tạm dừng.</p></div>',15)])])}const k=i(a,[["render",l]]);export{u as __pageData,k as default};
